command:
const fd = await foundry.applications.api.DialogV2.wait({
  window: { title: "Test de Peur" },
  content: `
    <div class="form-group"><label>Difficulté</label>
      <select name="diff"><option value="1">Facile (1)</option><option value="2" selected>Moyen (2)</option>
      <option value="3">Difficile (3)</option><option value="4">Intimidant (4)</option><option value="5">Exceptionnel (5)</option></select></div>
    <div class="form-group"><label>Améliorations ([di]→[ch])</label><input type="number" name="upg" value="0" min="0" max="5"/></div>
    <div class="form-group"><label>Source (affichée aux joueurs)</label><input type="text" name="src" value="Quelque chose remue dans l'ombre…"/></div>`,
  buttons: [{ action: "ok", label: "Envoyer aux joueurs", default: true,
    callback: (event, button) => new (foundry.applications.ux?.FormDataExtended ?? FormDataExtended)(button.form).object }],
});
if (!fd) return;
const diff = Number(fd.diff), upg = Math.min(Number(fd.upg), diff);
const pool = { difficulty: diff - upg, challenge: upg };
await ChatMessage.create({
  content: `<h3>😱 Test de Peur</h3><p><em>${fd.src}</em></p>
    <p>Lancez <strong>Sang-froid</strong> ou <strong>Discipline</strong>.</p>
    <p style="font-size:.9em">Échec : 1 stress + [se] jusqu'à la fin de la rencontre · [th][th][th] ou [de] :
    le personnage cède à la panique (le MJ tranche) · [tr] : immunisé à cette source pour la scène.</p>
    <button class="ffg-pool-to-player">🎲 Lancer (le pool contient la difficulté)</button>`,
  flags: { starwarsffg: { dicePool: pool, description: "Test de Peur", roll: { data: {}, skillName: "Peur", item: {}, flavor: "", sound: null } } },
});
